#!/usr/bin/env node
/**
 * Build script that generates src/worker-bundle.ts
 *
 * Reads dist/view/index.html and all web templates, then writes them
 * as exported constants so the Cloudflare Worker (which has no filesystem)
 * can use them at runtime.
 */

import { readFile, writeFile } from "node:fs/promises";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const TEMPLATES_DIR = join(ROOT, "templates");
const VIEW_HTML_PATH = join(ROOT, "dist", "view", "index.html");
const OUTPUT_PATH = join(ROOT, "src", "worker-bundle.ts");

async function main() {
  // 1. Read the view HTML
  console.log("Reading dist/view/index.html...");
  const viewHtml = await readFile(VIEW_HTML_PATH, "utf-8");
  console.log(`  View HTML: ${(viewHtml.length / 1024).toFixed(1)} KB`);

  // 2. Read templates/index.json (include both web and mobile)
  console.log("Reading templates/index.json...");
  const indexJson = JSON.parse(await readFile(join(TEMPLATES_DIR, "index.json"), "utf-8"));
  const allTemplates = indexJson.templates.filter((t) => t.platform === "web" || t.platform === "mobile");
  const webCount = allTemplates.filter((t) => t.platform === "web").length;
  const mobileCount = allTemplates.filter((t) => t.platform === "mobile").length;
  console.log(`  Found ${webCount} web + ${mobileCount} mobile templates (${allTemplates.length} total)`);

  // 3. Read each template's HTML file
  const bundledTemplates = [];
  let totalTemplateSize = 0;

  for (const entry of allTemplates) {
    const html = await readFile(join(TEMPLATES_DIR, entry.path), "utf-8");
    totalTemplateSize += html.length;
    bundledTemplates.push({
      name: entry.name,
      platform: entry.platform,
      questionType: entry.questionType,
      instructions: entry.instructions,
      controls: entry.controls,
      code: html,
    });
  }
  console.log(`  Total template HTML: ${(totalTemplateSize / 1024).toFixed(1)} KB`);

  // 4. Generate the TypeScript source
  // Use JSON.stringify for safe string embedding (handles all escaping)
  const output = `// AUTO-GENERATED by scripts/build-worker-bundle.mjs — DO NOT EDIT
// Generated at: ${new Date().toISOString()}

export const WIDGET_HTML: string = ${JSON.stringify(viewHtml)};

export interface BundledTemplate {
  name: string;
  platform: string;
  questionType: string;
  instructions: string;
  controls: unknown[];
  code: string;
}

export const WORKER_TEMPLATES: BundledTemplate[] = JSON.parse(${JSON.stringify(JSON.stringify(bundledTemplates))});
`;

  await writeFile(OUTPUT_PATH, output, "utf-8");
  const outputSize = (Buffer.byteLength(output) / 1024 / 1024).toFixed(2);
  console.log(`\nWrote ${OUTPUT_PATH}`);
  console.log(`  Bundle size: ${outputSize} MB`);
  console.log("Done!");
}

main().catch((err) => {
  console.error("Build failed:", err);
  process.exit(1);
});
